const body = $input.first().json.body || $input.first().json;

const user_id = body.user_id || null;
if (!user_id) throw new Error('Missing required field: user_id');

return [{ json: { user_id, now: new Date().toISOString() } }];

const items = $input.all();
const origin = $('Parse & Validate').first().json;

if (!items || items.length < 2) {
  throw new Error(`Expected 2 fetch results (ai_config + entitlements), got ${items?.length || 0}`);
}

const aiRaw = items[0].json;
const entRaw = items[1].json;

const aiConfig = Array.isArray(aiRaw) ? aiRaw[0] : aiRaw;
const ent = Array.isArray(entRaw) ? entRaw[0] : entRaw;

if (!aiConfig || !aiConfig.user_id) {
  throw new Error(`No ai_operator_config found for user_id: ${origin.user_id}. Run Business Profile AI Config Builder first.`);
}
if (!ent || !ent.user_id === undefined) {
  throw new Error(`No user_entitlements found for user_id: ${origin.user_id}.`);
}

// Tool metadata: name, description, what config fields Claude should generate
const toolMeta = {
  launchpad_tool_1: {
    name: 'AI Lead Finder',
    description: 'Finds and qualifies high-intent prospects',
    config_fields: 'target_industry, ideal_company_size, decision_maker_title, pain_point_keywords (array of 5), geographic_focus, lead_volume_per_run (integer), qualification_criteria (array of 3 strings)'
  },
  launchpad_tool_2: {
    name: 'Copy Generator',
    description: 'Generates conversion-ready copy for any channel',
    config_fields: 'brand_voice, primary_cta, tone (formal/conversational/bold), product_or_service_name, key_benefit_1, key_benefit_2, key_benefit_3, target_audience_description, default_word_count (integer)'
  },
  launchpad_tool_3: {
    name: 'Offer Builder',
    description: 'Structures irresistible offers',
    config_fields: 'core_transformation, price_point_range, delivery_format (1:1/group/digital/done-for-you), guarantee_type, bonus_stack (array of 3), urgency_mechanism, ideal_client_result'
  },
  launchpad_tool_4: {
    name: 'Email Sequencer',
    description: 'Builds automated follow-up email sequences',
    config_fields: 'sequence_length (integer 3-10), primary_goal (book_call/sell_product/nurture/re-engage), sender_first_name, send_days (array of integers), subject_line_style (question/statement/curiosity), open_with (story/stat/question), default_cta'
  },
  launchpad_tool_5: {
    name: 'Funnel Mapper',
    description: 'Visualises and optimises sales funnels',
    config_fields: 'funnel_type (lead_gen/sales/webinar/product/service), top_of_funnel_channel, average_deal_value (integer), typical_sales_cycle_days (integer), current_conversion_bottleneck, funnel_stages (array of stage names)'
  },
  launchpad_tool_6: {
    name: 'Competitor Analyst',
    description: 'Reverse-engineers competitor strategies',
    config_fields: 'analysis_focus (pricing/messaging/traffic/offers/all), known_competitors (array of up to 5 names), primary_differentiator, market_position (premium/mid/budget), intel_priority (array of 3 areas to investigate)'
  },
  launchpad_tool_7: {
    name: 'Ad Creative Studio',
    description: 'Produces ad concepts and copy',
    config_fields: 'primary_ad_platform (facebook/google/linkedin/tiktok/youtube), ad_format (image/video/carousel), hook_style (pain/desire/curiosity/social_proof), offer_in_ad, target_demographic, budget_tier (low/mid/high), desired_ctr_benchmark'
  },
  launchpad_tool_8: {
    name: 'VSL Script Writer',
    description: 'Writes video sales letter scripts',
    config_fields: 'vsl_length_minutes (integer 3-30), opening_hook_type (bold_claim/story/question/stat), problem_agitate_style, social_proof_type (testimonials/case_studies/credentials/results), cta_placement (early/middle/end/multiple), price_reveal_strategy'
  },
  launchpad_tool_9: {
    name: 'AI Sales Closer',
    description: 'AI-powered sales scripts and objection handling',
    config_fields: 'sales_format (discovery_call/demo/proposal/chat), average_deal_size, top_objection_1, top_objection_2, top_objection_3, closing_technique (assumptive/alternative_choice/urgency/value_stack), follow_up_cadence_days'
  },
  launchpad_tool_10: {
    name: 'Business Automator',
    description: 'Automates back-office operations',
    config_fields: 'automation_priority (lead_followup/invoicing/scheduling/reporting/onboarding), current_manual_task_1, current_manual_task_2, team_size (integer), tools_in_stack (array of current software names), hours_per_week_on_manual_tasks (integer)'
  }
};

// Build list of enabled tools
const enabledTools = Object.keys(toolMeta).filter(key => ent[key] === true);

if (enabledTools.length === 0) {
  throw new Error(`User ${origin.user_id} has no enabled launchpad tools in user_entitlements.`);
}

return [{
  json: {
    user_id:      origin.user_id,
    now:          origin.now,
    ai_config:    aiConfig,
    enabled_tools: enabledTools,
    tool_meta:    toolMeta,
    tool_count:   enabledTools.length
  }
}];

// Explode enabled tools into individual items for per-tool processing
const origin = $input.first().json;
const { user_id, now, ai_config, enabled_tools, tool_meta } = origin;

// Build one output item per enabled tool
const items = enabled_tools.map(tool_id => ({
  json: {
    user_id,
    now,
    tool_id,
    tool_name:         tool_meta[tool_id].name,
    tool_description:  tool_meta[tool_id].description,
    config_fields:     tool_meta[tool_id].config_fields,
    ai_config,
    total_tools:       enabled_tools.length
  }
}));

return items;

// Build Claude prompt for this specific tool
const d = $input.first().json;
const ai = d.ai_config;

const systemPrompt = `You are an AI business configuration engine for Nova OPS. Given a user's business profile and operator config, generate the ideal default configuration for the ${d.tool_name} tool. Return ONLY a valid JSON object — no markdown, no backticks, no explanation. Your entire response must be parseable by JSON.parse().`;

const userMessage = `Generate the default configuration for the "${d.tool_name}" tool (${d.tool_description}) for this business.

Business Profile:
- Operator Name: ${ai.operator_name || 'AI Operator'}
- Operator Tone: ${ai.operator_tone || 'professional'}
- Primary Niche: ${ai.primary_niche || 'General Business'}
- Target Customer Profile: ${ai.target_customer_profile || 'Business owners'}
- Top Pain Points: ${JSON.stringify(ai.top_3_pain_points || [])}
- GTM Strategy: ${ai.gtm_strategy_summary || 'Grow revenue through automation'}
- Brand Voice Keywords: ${JSON.stringify(ai.brand_voice_keywords || [])}

Generate a JSON config object with these exact fields (fill each with a sensible, specific default based on the business profile above):
${d.config_fields}

Rules:
- Be specific — use actual niche-relevant values, not generic placeholders
- Align tone and language with the operator_tone: ${ai.operator_tone || 'professional'}
- Arrays should have the exact number of items specified
- Integer fields must be actual integers
- Respond ONLY with the raw JSON object`;

return [{
  json: {
    ...d,
    system_prompt: systemPrompt,
    user_message:  userMessage
  }
}];

const claudeResponse = $input.first().json;
// Retrieve the originating tool context — passed through item pairing
const toolContext = $('Build Claude Prompt Per Tool').first().json;

// Extract text from Claude response
const content = claudeResponse?.content;
if (!content || !Array.isArray(content) || content.length === 0) {
  throw new Error(`Claude returned no content for tool ${toolContext.tool_id}`);
}

const rawText = content
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('')
  .trim();

// Strip accidental markdown fences
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let default_config;
try {
  default_config = JSON.parse(cleaned);
} catch (e) {
  // Non-fatal: store raw text with error flag rather than failing entire batch
  console.warn(`JSON parse failed for tool ${toolContext.tool_id}: ${e.message}. Storing raw.`);
  default_config = { _parse_error: true, _raw: cleaned.substring(0, 500) };
}

return [{
  json: {
    user_id:       toolContext.user_id,
    now:           toolContext.now,
    tool_id:       toolContext.tool_id,
    tool_name:     toolContext.tool_name,
    default_config,
    parse_ok:      !default_config._parse_error,
    total_tools:   toolContext.total_tools
  }
}];

// Collect all per-tool INSERT results and build summary
const items = $input.all();
const origin = $('Parse & Validate').first().json;

const total    = items.length;
const inserted = items.filter(i => {
  const r = Array.isArray(i.json) ? i.json[0] : i.json;
  return r?.user_id !== undefined;
}).length;

const tool_ids = items.map(i => {
  const r = Array.isArray(i.json) ? i.json[0] : i.json;
  return r?.tool_id || 'unknown';
});

const all_ok = inserted === total;

return [{
  json: {
    user_id:       origin.user_id,
    now:           origin.now,
    tools_processed: total,
    tools_inserted:  inserted,
    tool_ids,
    all_ok
  }
}];
